import React from 'react';
import { 
  AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer,
  PieChart, Pie, Cell, Legend
} from 'recharts';
import { Transaction, Category } from '../types';

interface ChartsProps {
  transactions: Transaction[];
  categories: Category[];
}

export const CashFlowChart: React.FC<ChartsProps> = ({ transactions }) => {
  // Aggregate data by date
  const data = transactions.reduce((acc: any[], t) => {
    const date = t.date.split('T')[0];
    const existing = acc.find(d => d.date === date);

    if (existing) {
      if (t.type === 'INCOME') existing.income += t.amount;
      if (t.type === 'EXPENSE') existing.expense += t.amount;
    } else {
      acc.push({
        date,
        income: t.type === 'INCOME' ? t.amount : 0,
        expense: t.type === 'EXPENSE' ? t.amount : 0
      });
    }
    return acc;
  }, []).sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime());

  // If empty, add dummy data for visuals
  if (data.length === 0) {
      const today = new Date();
      for(let i=6; i>=0; i--) {
          const d = new Date(today);
          d.setDate(d.getDate() - i);
          data.push({ date: d.toISOString().split('T')[0], income: 0, expense: 0 });
      }
  }

  return (
    <div className="h-[300px] w-full bg-white dark:bg-gray-800 p-4 rounded-xl shadow-sm border border-gray-100 dark:border-gray-700">
      <h3 className="text-lg font-semibold mb-4 text-gray-700 dark:text-gray-200">Cash Flow (7 Days)</h3>
      <ResponsiveContainer width="100%" height="100%">
        <AreaChart data={data}>
          <defs>
            <linearGradient id="colorIncome" x1="0" y1="0" x2="0" y2="1">
              <stop offset="5%" stopColor="#10b981" stopOpacity={0.8}/>
              <stop offset="95%" stopColor="#10b981" stopOpacity={0}/>
            </linearGradient>
            <linearGradient id="colorExpense" x1="0" y1="0" x2="0" y2="1">
              <stop offset="5%" stopColor="#ef4444" stopOpacity={0.8}/>
              <stop offset="95%" stopColor="#ef4444" stopOpacity={0}/>
            </linearGradient>
          </defs>
          <XAxis dataKey="date" stroke="#94a3b8" fontSize={12} tickFormatter={(val) => val.slice(5)} />
          <YAxis stroke="#94a3b8" fontSize={12} />
          <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#e2e8f0" />
          <Tooltip 
            contentStyle={{ backgroundColor: '#1e293b', border: 'none', borderRadius: '8px', color: '#fff' }}
            itemStyle={{ color: '#fff' }}
          />
          <Area type="monotone" dataKey="income" stroke="#10b981" fillOpacity={1} fill="url(#colorIncome)" />
          <Area type="monotone" dataKey="expense" stroke="#ef4444" fillOpacity={1} fill="url(#colorExpense)" />
        </AreaChart>
      </ResponsiveContainer>
    </div>
  );
};

export const ExpenseBreakdown: React.FC<ChartsProps> = ({ transactions, categories }) => {
  const data = transactions
    .filter(t => t.type === 'EXPENSE' && t.categoryId)
    .reduce((acc: any[], t) => {
      const cat = categories.find(c => c.id === t.categoryId);
      if (!cat) return acc;

      const existing = acc.find(d => d.name === cat.name);
      if (existing) {
        existing.value += t.amount;
      } else {
        acc.push({ name: cat.name, value: t.amount, color: cat.color });
      }
      return acc;
    }, []);

  if (data.length === 0) {
      data.push({ name: 'No Data', value: 100, color: '#e2e8f0' });
  }

  return (
    <div className="h-[300px] w-full bg-white dark:bg-gray-800 p-4 rounded-xl shadow-sm border border-gray-100 dark:border-gray-700">
      <h3 className="text-lg font-semibold mb-4 text-gray-700 dark:text-gray-200">Expense by Category</h3>
      <ResponsiveContainer width="100%" height="100%">
        <PieChart>
          <Pie
            data={data}
            cx="50%"
            cy="50%"
            innerRadius={60}
            outerRadius={80}
            paddingAngle={5}
            dataKey="value"
          >
            {data.map((entry, index) => (
              <Cell key={`cell-${index}`} fill={entry.color} />
            ))}
          </Pie>
          <Tooltip 
            contentStyle={{ backgroundColor: '#1e293b', border: 'none', borderRadius: '8px', color: '#fff' }}
            itemStyle={{ color: '#fff' }}
          />
          <Legend />
        </PieChart>
      </ResponsiveContainer>
    </div>
  );
};

import React, { useState } from 'react';
import { Icons } from './Icons';
import { AppState, Category, FinancialContext } from '../types';

interface ModalProps {
  isOpen: boolean;
  onClose: () => void;
  title: string;
  children: React.ReactNode;
}

const Modal: React.FC<ModalProps> = ({ isOpen, onClose, title, children }) => {
  if (!isOpen) return null;
  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm p-4">
      <div className="bg-white dark:bg-slate-800 rounded-2xl w-full max-w-lg shadow-2xl overflow-hidden max-h-[90vh] flex flex-col">
        <div className="p-4 border-b border-gray-100 dark:border-gray-700 flex justify-between items-center bg-gray-50 dark:bg-slate-900">
          <h2 className="text-xl font-bold text-gray-800 dark:text-white">{title}</h2>
          <button onClick={onClose} className="p-2 hover:bg-gray-200 dark:hover:bg-slate-700 rounded-full transition-colors">
            <Icons.LogOut className="w-5 h-5" />
          </button>
        </div>
        <div className="p-6 overflow-y-auto">
          {children}
        </div>
      </div>
    </div>
  );
};

// --- Generic Form Field Helpers ---

const Input = (props: any) => (
    <div className="mb-4">
        <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">{props.label}</label>
        <input {...props} className="w-full px-3 py-2 bg-white dark:bg-slate-700 border border-gray-300 dark:border-slate-600 rounded-lg focus:ring-2 focus:ring-primary focus:border-transparent outline-none transition-all dark:text-white" />
    </div>
);

const Select = (props: any) => (
    <div className="mb-4">
        <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">{props.label}</label>
        <select {...props} className="w-full px-3 py-2 bg-white dark:bg-slate-700 border border-gray-300 dark:border-slate-600 rounded-lg focus:ring-2 focus:ring-primary focus:border-transparent outline-none transition-all dark:text-white">
            {props.children}
        </select>
    </div>
);

// --- Specific Forms ---

interface TransactionFormProps {
    type: 'EXPENSE' | 'INCOME';
    state: AppState;
    onSubmit: (data: any) => void;
    onClose: () => void;
}

export const TransactionForm: React.FC<TransactionFormProps> = ({ type, state, onSubmit, onClose }) => {
    const [contextId, setContextId] = useState(state.contexts[0]?.id || '');
    const [accountId, setAccountId] = useState('');
    const [subAccountId, setSubAccountId] = useState('');
    const [amount, setAmount] = useState('');
    const [categoryId, setCategoryId] = useState('');
    const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
    const [notes, setNotes] = useState('');

    const activeContext = state.contexts.find(c => c.id === contextId);
    const activeAccount = activeContext?.accounts.find(a => a.id === accountId);

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        onSubmit({ type, contextId, accountId, subAccountId, amount: Number(amount), categoryId, date, notes });
        onClose();
    };

    return (
        <Modal isOpen={true} onClose={onClose} title={`New ${type === 'EXPENSE' ? 'Expense' : 'Income'}`}>
            <form onSubmit={handleSubmit}>
                <Input type="text" label="Description" required placeholder="e.g. Walmart, Client Invoice" onChange={(e: any) => setNotes(e.target.value)} />
                <Input type="number" label="Amount" required min="0" step="0.01" value={amount} onChange={(e: any) => setAmount(e.target.value)} />

                <div className="grid grid-cols-2 gap-4">
                    <Select label="Context" value={contextId} onChange={(e: any) => setContextId(e.target.value)}>
                        {state.contexts.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                    </Select>
                    <Input type="date" label="Date" value={date} onChange={(e: any) => setDate(e.target.value)} />
                </div>

                <Select label="Account" value={accountId} onChange={(e: any) => { setAccountId(e.target.value); setSubAccountId(''); }}>
                    <option value="">Select Account</option>
                    {activeContext?.accounts.map(a => <option key={a.id} value={a.id}>{a.name}</option>)}
                </Select>

                {activeAccount && activeAccount.subAccounts.length > 0 && (
                    <Select label="Sub-Account (Optional)" value={subAccountId} onChange={(e: any) => setSubAccountId(e.target.value)}>
                        <option value="">None</option>
                        {activeAccount.subAccounts.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                    </Select>
                )}

                {type === 'EXPENSE' && (
                    <Select label="Category" value={categoryId} onChange={(e: any) => setCategoryId(e.target.value)}>
                        <option value="">Select Category</option>
                        {state.categories.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                    </Select>
                )}

                <button type="submit" className={`w-full py-3 rounded-lg text-white font-bold shadow-lg mt-4 ${type === 'EXPENSE' ? 'bg-red-500 hover:bg-red-600' : 'bg-green-500 hover:bg-green-600'}`}>
                    Save {type === 'EXPENSE' ? 'Expense' : 'Income'}
                </button>
            </form>
        </Modal>
    );
};

interface TransferFormProps {
    state: AppState;
    onSubmit: (data: any) => void;
    onClose: () => void;
}

export const TransferForm: React.FC<TransferFormProps> = ({ state, onSubmit, onClose }) => {
    // Source
    const [fromContext, setFromContext] = useState(state.contexts[0]?.id || '');
    const [fromAccount, setFromAccount] = useState('');
    const [fromSub, setFromSub] = useState('');

    // Dest
    const [toContext, setToContext] = useState(state.contexts[0]?.id || '');
    const [toAccount, setToAccount] = useState('');
    const [toSub, setToSub] = useState('');

    const [amount, setAmount] = useState('');
    const [notes, setNotes] = useState('');

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        onSubmit({ 
            type: 'TRANSFER', 
            amount: Number(amount), date: new Date().toISOString(), notes,
            contextId: fromContext, accountId: fromAccount, subAccountId: fromSub,
            toContextId: toContext, toAccountId: toAccount, toSubAccountId: toSub
        });
        onClose();
    };

    const getContext = (id: string) => state.contexts.find(c => c.id === id);
    const getAccount = (ctxId: string, accId: string) => getContext(ctxId)?.accounts.find(a => a.id === accId);

    return (
        <Modal isOpen={true} onClose={onClose} title="New Transfer">
            <form onSubmit={handleSubmit} className="space-y-4">
                <Input type="number" label="Amount" required value={amount} onChange={(e: any) => setAmount(e.target.value)} />

                <div className="grid grid-cols-1 md:grid-cols-2 gap-6 bg-gray-50 dark:bg-slate-700/30 p-4 rounded-xl">
                    {/* FROM */}
                    <div>
                        <h4 className="font-bold text-red-500 mb-2 text-sm uppercase">From</h4>
                        <Select label="Context" value={fromContext} onChange={(e: any) => setFromContext(e.target.value)}>
                            {state.contexts.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                        </Select>
                        <Select label="Account" value={fromAccount} onChange={(e: any) => setFromAccount(e.target.value)}>
                            <option value="">Select Account</option>
                            {getContext(fromContext)?.accounts.map(a => <option key={a.id} value={a.id}>{a.name}</option>)}
                        </Select>
                         <Select label="Sub (Opt)" value={fromSub} onChange={(e: any) => setFromSub(e.target.value)}>
                            <option value="">None</option>
                            {getAccount(fromContext, fromAccount)?.subAccounts.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                        </Select>
                    </div>

                    {/* TO */}
                    <div>
                        <h4 className="font-bold text-green-500 mb-2 text-sm uppercase">To</h4>
                        <Select label="Context" value={toContext} onChange={(e: any) => setToContext(e.target.value)}>
                            {state.contexts.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                        </Select>
                        <Select label="Account" value={toAccount} onChange={(e: any) => setToAccount(e.target.value)}>
                            <option value="">Select Account</option>
                            {getContext(toContext)?.accounts.map(a => <option key={a.id} value={a.id}>{a.name}</option>)}
                        </Select>
                         <Select label="Sub (Opt)" value={toSub} onChange={(e: any) => setToSub(e.target.value)}>
                            <option value="">None</option>
                            {getAccount(toContext, toAccount)?.subAccounts.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                        </Select>
                    </div>
                </div>

                <Input type="text" label="Notes" value={notes} onChange={(e: any) => setNotes(e.target.value)} />
                <button type="submit" className="w-full py-3 bg-blue-600 hover:bg-blue-700 rounded-lg text-white font-bold shadow-lg">Transfer Funds</button>
            </form>
        </Modal>
    );
};

export const SubAccountForm: React.FC<any> = ({ state, onSubmit, onClose }) => {
