             <form onSubmit={(e) => { e.preventDefault(); onSubmit({ name, amount: Number(amount), frequency, nextRenewal, contextId, accountId, active: true, paymentMethod: 'Card' }); onClose(); }}>
                <Input type="text" label="Service Name" required value={name} onChange={(e: any) => setName(e.target.value)} />
                <Input type="number" label="Amount" required value={amount} onChange={(e: any) => setAmount(e.target.value)} />
                <Select label="Frequency" value={frequency} onChange={(e: any) => setFrequency(e.target.value)}>
                    <option value="WEEKLY">Weekly</option>
                    <option value="MONTHLY">Monthly</option>
                    <option value="QUARTERLY">Quarterly</option>
                    <option value="ANNUAL">Annual</option>
                </Select>
                <Input type="date" label="Next Renewal" required value={nextRenewal} onChange={(e: any) => setNextRenewal(e.target.value)} />

                <Select label="Payment Context" value={contextId} onChange={(e: any) => setContextId(e.target.value)}>
                    {state.contexts.map((c: any) => <option key={c.id} value={c.id}>{c.name}</option>)}
                </Select>
                <Select label="Payment Account" value={accountId} onChange={(e: any) => setAccountId(e.target.value)}>
                    <option value="">Select Account</option>
                    {state.contexts.find((c:any) => c.id === contextId)?.accounts.map((a:any) => <option key={a.id} value={a.id}>{a.name}</option>)}
                </Select>

                <button type="submit" className="w-full py-3 bg-pink-600 hover:bg-pink-700 text-white font-bold rounded-lg">Add Subscription</button>
            </form>
        </Modal>
    )
}

import React from 'react';
