import React, { useState, useEffect } from 'react';
import { AppState, FinancialContext, Transaction, Subscription, Category } from './types';
import { INITIAL_STATE } from './constants';
import { Icons } from './components/Icons';
import { CashFlowChart, ExpenseBreakdown } from './components/Charts';
import { AccountsView } from './components/AccountsView';
import { TransactionForm, TransferForm, CategoryForm, SubAccountForm, SubscriptionForm } from './components/ActionModals';

type View = 'DASHBOARD' | 'ACCOUNTS' | 'TRANSACTIONS' | 'SUBSCRIPTIONS' | 'SETTINGS';

function App() {
  const [state, setState] = useState<AppState>(INITIAL_STATE);
  const [currentView, setCurrentView] = useState<View>('DASHBOARD');
  const [contextFilter, setContextFilter] = useState<string>('ALL');

  // Modal States
  const [activeModal, setActiveModal] = useState<string | null>(null);

  // Helper to handle dark mode
  useEffect(() => {
    if (state.user.darkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [state.user.darkMode]);

  // --- Actions ---

  const handleTransaction = (data: any) => {
    // 1. Create Transaction Record
    const newTx: Transaction = {
        id: `tx_${Date.now()}`,
        ...data
    };

    // 2. Update Balances
    const newContexts = [...state.contexts];
    const ctxIdx = newContexts.findIndex(c => c.id === data.contextId);
    if (ctxIdx > -1) {
        const accIdx = newContexts[ctxIdx].accounts.findIndex(a => a.id === data.accountId);
        if (accIdx > -1) {
            const acc = newContexts[ctxIdx].accounts[accIdx];

            // Handle Sub-account or Main Account Balance
            if (data.subAccountId) {
                const subIdx = acc.subAccounts.findIndex(s => s.id === data.subAccountId);
                if (subIdx > -1) {
                    acc.subAccounts[subIdx].balance += (data.type === 'INCOME' ? data.amount : -data.amount);
                }
            } else {
                acc.balance += (data.type === 'INCOME' ? data.amount : -data.amount);
            }
        }
    }

    setState({
        ...state,
        transactions: [newTx, ...state.transactions],
        contexts: newContexts
    });
  };

  const handleTransfer = (data: any) => {
      // Logic for moving money between ANY account/sub-account
      const newContexts = [...state.contexts];

      const updateBalance = (ctxId: string, accId: string, subId: string | undefined, amount: number) => {
          const c = newContexts.find(c => c.id === ctxId);
          const a = c?.accounts.find(a => a.id === accId);
          if (a) {
              if (subId) {
                  const s = a.subAccounts.find(s => s.id === subId);
                  if (s) s.balance += amount;
              } else {
                  a.balance += amount;
              }
          }
      };

      // Remove from source
      updateBalance(data.contextId, data.accountId, data.subAccountId, -data.amount);
      // Add to dest
      updateBalance(data.toContextId, data.toAccountId, data.toSubAccountId, data.amount);

      const newTx: Transaction = {
          id: `tr_${Date.now()}`,
          ...data
      };

      setState({ ...state, contexts: newContexts, transactions: [newTx, ...state.transactions] });
  };

  const handleNewSubAccount = (data: any) => {
      const newContexts = [...state.contexts];
      const ctx = newContexts.find(c => c.id === data.contextId);
      const acc = ctx?.accounts.find(a => a.id === data.accountId);

      if (acc) {
          acc.subAccounts.push({
              id: `sub_${Date.now()}`,
              name: data.name,
              balance: 0,
              target: data.target,
              startDate: data.startDate
          });
          setState({ ...state, contexts: newContexts });
      }
  };

  const handleNewCategory = (data: any) => {
      setState({ ...state, categories: [...state.categories, { id: `c_${Date.now()}`, ...data, icon: 'Tags' }]});
  };

  const handleNewSubscription = (data: any) => {
      setState({ ...state, subscriptions: [...state.subscriptions, { id: `s_${Date.now()}`, ...data }]});
  };

  // --- Filtering ---

  const filteredTransactions = state.transactions.filter(t => 
      contextFilter === 'ALL' || t.contextId === contextFilter
  );

  const totalBalance = state.contexts
    .filter(c => contextFilter === 'ALL' || c.id === contextFilter)
    .reduce((acc, ctx) => {
        return acc + ctx.accounts.reduce((a, acc) => a + acc.balance + acc.subAccounts.reduce((s, sub) => s + sub.balance, 0), 0);
    }, 0);

  // --- Render ---

  return (
    <div className="flex h-screen bg-gray-50 dark:bg-slate-900 overflow-hidden">

      {/* Sidebar */}
      <aside className="w-64 bg-white dark:bg-slate-800 border-r border-gray-100 dark:border-gray-700 hidden md:flex flex-col">
        <div className="p-6">
            <h1 className="text-2xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-blue-600 to-teal-500">ProfitFlow</h1>
        </div>

        <nav className="flex-1 px-4 space-y-2">
            {[
                { id: 'DASHBOARD', icon: Icons.Dashboard, label: 'Dashboard' },
                { id: 'ACCOUNTS', icon: Icons.Accounts, label: 'Accounts & Goals' },
                { id: 'TRANSACTIONS', icon: Icons.Transfer, label: 'Transactions' },
                { id: 'SUBSCRIPTIONS', icon: Icons.Subscription, label: 'Subscriptions' },
                { id: 'SETTINGS', icon: Icons.Settings, label: 'Settings' },
            ].map((item) => (
                <button 
                    key={item.id}
                    onClick={() => setCurrentView(item.id as View)}
                    className={`w-full flex items-center space-x-3 px-4 py-3 rounded-xl transition-colors ${currentView === item.id ? 'bg-blue-50 text-blue-600 dark:bg-blue-900/20 dark:text-blue-400 font-semibold' : 'text-gray-600 dark:text-gray-400 hover:bg-gray-50 dark:hover:bg-gray-800'}`}
                >
                    <item.icon className="w-5 h-5" />
                    <span>{item.label}</span>
                </button>
            ))}
        </nav>

        <div className="p-4 border-t border-gray-100 dark:border-gray-700">
            <div className="flex items-center gap-3 p-2 rounded-lg hover:bg-gray-50 dark:hover:bg-gray-800 cursor-pointer">
                <div className="w-10 h-10 rounded-full bg-gradient-to-tr from-purple-500 to-blue-500 flex items-center justify-center text-white font-bold">
                    {state.user.name.charAt(0)}
                </div>
                <div>
                    <p className="text-sm font-semibold">{state.user.name}</p>
                    <p className="text-xs text-gray-500">Free Plan</p>
                </div>
            </div>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 flex flex-col overflow-hidden relative">
        {/* Top Header */}
        <header className="h-16 bg-white dark:bg-slate-800 border-b border-gray-100 dark:border-gray-700 flex items-center justify-between px-6 z-10">
            <div className="flex items-center gap-4">
                <select 
                    value={contextFilter} 
                    onChange={(e) => setContextFilter(e.target.value)}
                    className="bg-gray-100 dark:bg-slate-700 border-none rounded-lg py-2 px-3 text-sm font-medium focus:ring-2 focus:ring-primary"
                >
                    <option value="ALL">Global View</option>
                    {state.contexts.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                </select>
                <div className="hidden md:block h-6 w-px bg-gray-200 dark:bg-gray-600"></div>
                <div className="text-sm font-medium text-gray-500">
                    Net Worth: <span className="text-gray-900 dark:text-white font-bold text-lg">${totalBalance.toLocaleString()}</span>
                </div>
            </div>

            <div className="flex gap-2">
                <button onClick={() => setState({...state, user: {...state.user, darkMode: !state.user.darkMode}})} className="p-2 rounded-full hover:bg-gray-100 dark:hover:bg-slate-700">
                    {state.user.darkMode ? <Icons.Sun className="w-5 h-5"/> : <Icons.Moon className="w-5 h-5"/>}
                </button>
            </div>
        </header>

        {/* Scrollable Area */}
        <div className="flex-1 overflow-y-auto p-4 md:p-8">

            {/* Quick Actions (Sticky on Mobile, Top on Desktop) */}
            <div className="grid grid-cols-3 md:grid-cols-6 gap-3 mb-8">
                {[
                    { label: 'Expense', icon: Icons.Expense, color: 'text-red-500', bg: 'bg-red-50 dark:bg-red-900/10', action: () => setActiveModal('EXPENSE') },
                    { label: 'Income', icon: Icons.Income, color: 'text-green-500', bg: 'bg-green-50 dark:bg-green-900/10', action: () => setActiveModal('INCOME') },
                    { label: 'Transfer', icon: Icons.Transfer, color: 'text-blue-500', bg: 'bg-blue-50 dark:bg-blue-900/10', action: () => setActiveModal('TRANSFER') },
                    { label: 'Subscrip.', icon: Icons.Subscription, color: 'text-purple-500', bg: 'bg-purple-50 dark:bg-purple-900/10', action: () => setActiveModal('SUBSCRIPTION') },
                    { label: 'Category', icon: Icons.Category, color: 'text-orange-500', bg: 'bg-orange-50 dark:bg-orange-900/10', action: () => setActiveModal('CATEGORY') },
                    { label: 'Sub-Acc', icon: Icons.Accounts, color: 'text-teal-500', bg: 'bg-teal-50 dark:bg-teal-900/10', action: () => setActiveModal('SUB_ACCOUNT') },
                ].map((btn, i) => (
                    <button key={i} onClick={btn.action} className="flex flex-col items-center justify-center p-3 rounded-xl bg-white dark:bg-slate-800 shadow-sm border border-gray-100 dark:border-gray-700 hover:shadow-md transition-all active:scale-95 group">
                        <div className={`p-2 rounded-full mb-2 ${btn.bg} group-hover:bg-opacity-80`}>
                            <btn.icon className={`w-6 h-6 ${btn.color}`} />
                        </div>
                        <span className="text-xs font-medium text-gray-600 dark:text-gray-300">{btn.label}</span>
                    </button>
                ))}
            </div>

            {/* View Content */}
            {currentView === 'DASHBOARD' && (
                <div className="space-y-6">
                    <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                        <CashFlowChart transactions={filteredTransactions} categories={state.categories} />
                        <ExpenseBreakdown transactions={filteredTransactions} categories={state.categories} />
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                         {/* Recent Transactions List */}
                        <div className="bg-white dark:bg-slate-800 rounded-xl shadow-sm border border-gray-100 dark:border-gray-700 p-4">
                            <h3 className="font-bold text-lg mb-4">Recent Transactions</h3>
                            <div className="space-y-3">
                                {filteredTransactions.slice(0, 5).map(t => (
                                    <div key={t.id} className="flex justify-between items-center p-3 rounded-lg hover:bg-gray-50 dark:hover:bg-slate-700/50">
                                        <div className="flex items-center gap-3">
                                            <div className={`p-2 rounded-full ${t.type === 'INCOME' ? 'bg-green-100 text-green-600' : 'bg-red-100 text-red-600'}`}>
                                                {t.type === 'INCOME' ? <Icons.Income className="w-4 h-4" /> : <Icons.Expense className="w-4 h-4" />}
                                            </div>
                                            <div>
                                                <p className="font-medium text-sm">{t.notes || 'Transaction'}</p>
                                                <p className="text-xs text-gray-500">{t.date}</p>
                                            </div>
                                        </div>
                                        <span className={`font-bold ${t.type === 'INCOME' ? 'text-green-600' : 'text-red-600'}`}>
                                            {t.type === 'INCOME' ? '+' : '-'}${t.amount.toLocaleString()}
                                        </span>
                                    </div>
                                ))}
                                {filteredTransactions.length === 0 && <p className="text-gray-400 text-sm text-center py-4">No transactions found.</p>}
                            </div>
                        </div>

                         {/* Upcoming Subs */}
                        <div className="bg-white dark:bg-slate-800 rounded-xl shadow-sm border border-gray-100 dark:border-gray-700 p-4">
                            <h3 className="font-bold text-lg mb-4">Upcoming Renewals</h3>
                            <div className="space-y-3">
                                {state.subscriptions.filter(s => s.active).map(s => (
                                    <div key={s.id} className="flex justify-between items-center p-3 rounded-lg border border-gray-100 dark:border-slate-700">
                                        <div className="flex items-center gap-3">
                                            <div className="p-2 bg-purple-100 text-purple-600 rounded-lg">
                                                <Icons.Subscription className="w-4 h-4" />
                                            </div>
                                            <div>
                                                <p className="font-medium text-sm">{s.name}</p>
                                                <p className="text-xs text-gray-500">{s.frequency} • {s.nextRenewal}</p>
                                            </div>
                                        </div>
                                        <span className="font-bold text-gray-700 dark:text-gray-300">${s.amount}</span>
                                    </div>
                                ))}
                            </div>
                        </div>
                    </div>
                </div>
            )}

            {currentView === 'ACCOUNTS' && (
                <AccountsView contexts={state.contexts.filter(c => contextFilter === 'ALL' || c.id === contextFilter)} />
            )}

            {currentView === 'TRANSACTIONS' && (
                <div className="bg-white dark:bg-slate-800 rounded-xl shadow-sm overflow-hidden">
                    <table className="w-full text-left border-collapse">
                        <thead className="bg-gray-50 dark:bg-slate-700 text-xs uppercase text-gray-500 dark:text-gray-400">
                            <tr>
                                <th className="p-4">Date</th>
                                <th className="p-4">Type</th>
                                <th className="p-4">Description</th>
                                <th className="p-4">Category</th>
                                <th className="p-4 text-right">Amount</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-gray-100 dark:divide-slate-700">
                            {filteredTransactions.map(t => (
                                <tr key={t.id} className="hover:bg-gray-50 dark:hover:bg-slate-700/50">
                                    <td className="p-4 text-sm text-gray-600 dark:text-gray-300">{t.date}</td>
                                    <td className="p-4"><span className={`text-xs font-bold px-2 py-1 rounded ${t.type === 'INCOME' ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'}`}>{t.type}</span></td>
                                    <td className="p-4 text-sm font-medium">{t.notes}</td>
                                    <td className="p-4 text-sm text-gray-500">
                                        {t.categoryId && state.categories.find(c => c.id === t.categoryId)?.name}
                                    </td>
                                    <td className={`p-4 text-right font-mono font-bold ${t.type === 'INCOME' ? 'text-green-600' : 'text-red-600'}`}>
                                        ${t.amount.toLocaleString()}
                                    </td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                </div>
            )}
        </div>
      </main>

      {/* Modals */}
      {activeModal === 'EXPENSE' && <TransactionForm type="EXPENSE" state={state} onSubmit={handleTransaction} onClose={() => setActiveModal(null)} />}
      {activeModal === 'INCOME' && <TransactionForm type="INCOME" state={state} onSubmit={handleTransaction} onClose={() => setActiveModal(null)} />}
      {activeModal === 'TRANSFER' && <TransferForm state={state} onSubmit={handleTransfer} onClose={() => setActiveModal(null)} />}
      {activeModal === 'CATEGORY' && <CategoryForm onSubmit={handleNewCategory} onClose={() => setActiveModal(null)} />}
      {activeModal === 'SUB_ACCOUNT' && <SubAccountForm state={state} onSubmit={handleNewSubAccount} onClose={() => setActiveModal(null)} />}
      {activeModal === 'SUBSCRIPTION' && <SubscriptionForm state={state} onSubmit={handleNewSubscription} onClose={() => setActiveModal(null)} />}

    </div>
  );
}

export default App;

