import React from 'react';
import { 
  AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer,
  PieChart, Pie, Cell, Legend
} from 'recharts';
import { Transaction, Category } from '../types';

interface ChartsProps {
  transactions: Transaction[];
  categories: Category[];
}

export const CashFlowChart: React.FC<ChartsProps> = ({ transactions }) => {
  // Aggregate data by date
  const data = transactions.reduce((acc: any[], t) => {
    const date = t.date.split('T')[0];
    const existing = acc.find(d => d.date === date);

    if (existing) {
      if (t.type === 'INCOME') existing.income += t.amount;
      if (t.type === 'EXPENSE') existing.expense += t.amount;
    } else {
      acc.push({
        date,
        income: t.type === 'INCOME' ? t.amount : 0,
        expense: t.type === 'EXPENSE' ? t.amount : 0
      });
    }
    return acc;
  }, []).sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime());

  // If empty, add dummy data for visuals
  if (data.length === 0) {
      const today = new Date();
      for(let i=6; i>=0; i--) {
          const d = new Date(today);
          d.setDate(d.getDate() - i);
          data.push({ date: d.toISOString().split('T')[0], income: 0, expense: 0 });
      }
  }

  return (
    <div className="h-[350px] w-full bg-white p-6 border border-black/5 hover:border-alloy transition-colors group">
      <div className="flex justify-between items-center mb-6">
          <div>
            <h3 className="font-display font-bold text-lg text-onyx">Cash Flow Velocity</h3>
            <p className="font-sans text-[10px] text-graphite uppercase tracking-widest mt-1">7 Day Trend</p>
          </div>
          <div className="w-8 h-[2px] bg-metallic"></div>
      </div>
      <ResponsiveContainer width="100%" height="80%">
        <AreaChart data={data}>
          <defs>
            <linearGradient id="colorIncome" x1="0" y1="0" x2="0" y2="1">
              <stop offset="5%" stopColor="#0E0E0F" stopOpacity={0.1}/>
              <stop offset="95%" stopColor="#0E0E0F" stopOpacity={0}/>
            </linearGradient>
            <linearGradient id="colorExpense" x1="0" y1="0" x2="0" y2="1">
              <stop offset="5%" stopColor="#D4A853" stopOpacity={0.1}/>
              <stop offset="95%" stopColor="#D4A853" stopOpacity={0}/>
            </linearGradient>
          </defs>
          <XAxis dataKey="date" stroke="#9ca3af" fontSize={10} tickFormatter={(val) => val.slice(5)} tickLine={false} axisLine={false} />
          <YAxis stroke="#9ca3af" fontSize={10} tickLine={false} axisLine={false} tickFormatter={(val) => `$${val}`} />
          <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f3f4f6" />
          <Tooltip 
            contentStyle={{ backgroundColor: '#0E0E0F', border: 'none', borderRadius: '0px', color: '#fff' }}
            itemStyle={{ color: '#fff', fontSize: '12px', fontFamily: 'Inter' }}
            cursor={{ stroke: '#C9A86A', strokeWidth: 1 }}
          />
          <Area type="monotone" dataKey="income" stroke="#0E0E0F" strokeWidth={2} fillOpacity={1} fill="url(#colorIncome)" />
          <Area type="monotone" dataKey="expense" stroke="#D4A853" strokeWidth={2} fillOpacity={1} fill="url(#colorExpense)" />
        </AreaChart>
      </ResponsiveContainer>
    </div>
  );
};

export const ExpenseBreakdown: React.FC<ChartsProps> = ({ transactions, categories }) => {
  const data = transactions
    .filter(t => t.type === 'EXPENSE' && t.categoryId)
    .reduce((acc: any[], t) => {
      const cat = categories.find(c => c.id === t.categoryId);
      if (!cat) return acc;

      const existing = acc.find(d => d.name === cat.name);
      if (existing) {
        existing.value += t.amount;
      } else {
        acc.push({ name: cat.name, value: t.amount, color: cat.color });
      }
      return acc;
    }, []);

  if (data.length === 0) {
      data.push({ name: 'No Data', value: 100, color: '#DEDEDE' });
  }

  return (
    <div className="h-[350px] w-full bg-white p-6 border border-black/5 hover:border-alloy transition-colors">
       <div className="flex justify-between items-center mb-6">
          <div>
            <h3 className="font-display font-bold text-lg text-onyx">Expense Allocation</h3>
            <p className="font-sans text-[10px] text-graphite uppercase tracking-widest mt-1">Categorical Split</p>
          </div>
          <div className="w-8 h-[2px] bg-metallic"></div>
      </div>
      <ResponsiveContainer width="100%" height="80%">
        <PieChart>
          <Pie
            data={data}
            cx="50%"
            cy="50%"
            innerRadius={60}
            outerRadius={80}
            paddingAngle={2}
            dataKey="value"
            stroke="none"
          >
            {data.map((entry, index) => (
              <Cell key={`cell-${index}`} fill={entry.color} />
            ))}
          </Pie>
          <Tooltip 
            contentStyle={{ backgroundColor: '#0E0E0F', border: 'none', borderRadius: '0px', color: '#fff' }}
            itemStyle={{ color: '#fff', fontSize: '12px' }}
          />
          <Legend 
            wrapperStyle={{ fontSize: '11px', fontFamily: 'Inter', color: '#4B4B4D' }}
            layout="vertical" verticalAlign="middle" align="right" 
          />
        </PieChart>
      </ResponsiveContainer>
    </div>
  );
};

import React, { useState } from 'react';
import { AppState, FinancialContext, Transaction, Subscription, Category, Account } from './types';
import { INITIAL_STATE } from './constants';
import { Icons } from './components/Icons';
import { CashFlowChart, ExpenseBreakdown } from './components/Charts';
import { AccountsView } from './components/AccountsView';
import { TransactionForm, TransferForm, CategoryForm, SubAccountForm, SubscriptionForm, NewContextForm } from './components/ActionModals';

type View = 'DASHBOARD' | 'ACCOUNTS' | 'TRANSACTIONS' | 'SUBSCRIPTIONS' | 'SETTINGS';

function App() {
  const [state, setState] = useState<AppState>(INITIAL_STATE);
  const [currentView, setCurrentView] = useState<View>('DASHBOARD');
  const [contextFilter, setContextFilter] = useState<string>('ALL');
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  // Modal States
  const [activeModal, setActiveModal] = useState<string | null>(null);

  // --- Actions ---

  const handleTransaction = (data: any) => {
    const newTx: Transaction = {
        id: `tx_${Date.now()}`,
        ...data
    };

    const newContexts = [...state.contexts];
    const ctxIdx = newContexts.findIndex(c => c.id === data.contextId);
    if (ctxIdx > -1) {
        const accIdx = newContexts[ctxIdx].accounts.findIndex(a => a.id === data.accountId);
        if (accIdx > -1) {
            const acc = newContexts[ctxIdx].accounts[accIdx];

            if (data.subAccountId) {
                const subIdx = acc.subAccounts.findIndex(s => s.id === data.subAccountId);
                if (subIdx > -1) {
                    acc.subAccounts[subIdx].balance += (data.type === 'INCOME' ? data.amount : -data.amount);
                }
            } else {
                acc.balance += (data.type === 'INCOME' ? data.amount : -data.amount);
            }
        }
    }

    setState({
        ...state,
        transactions: [newTx, ...state.transactions],
        contexts: newContexts
    });
  };

  const handleTransfer = (data: any) => {
      const newContexts = [...state.contexts];
      const updateBalance = (ctxId: string, accId: string, subId: string | undefined, amount: number) => {
          const c = newContexts.find(c => c.id === ctxId);
          const a = c?.accounts.find(a => a.id === accId);
          if (a) {
              if (subId) {
                  const s = a.subAccounts.find(s => s.id === subId);
                  if (s) s.balance += amount;
              } else {
                  a.balance += amount;
              }
          }
      };

      updateBalance(data.contextId, data.accountId, data.subAccountId, -data.amount);
      updateBalance(data.toContextId, data.toAccountId, data.toSubAccountId, data.amount);

      const newTx: Transaction = { id: `tr_${Date.now()}`, ...data };
      setState({ ...state, contexts: newContexts, transactions: [newTx, ...state.transactions] });
  };

  const handleNewSubAccount = (data: any) => {
      const newContexts = [...state.contexts];
      const ctx = newContexts.find(c => c.id === data.contextId);
      const acc = ctx?.accounts.find(a => a.id === data.accountId);
      if (acc) {
          acc.subAccounts.push({
              id: `sub_${Date.now()}`, name: data.name, balance: 0, target: data.target, startDate: data.startDate
          });
          setState({ ...state, contexts: newContexts });
      }
  };

  const handleNewCategory = (data: any) => {
      setState({ ...state, categories: [...state.categories, { id: `c_${Date.now()}`, ...data, icon: 'Tags' }]});
  };

  const handleNewSubscription = (data: any) => {
      setState({ ...state, subscriptions: [...state.subscriptions, { id: `s_${Date.now()}`, ...data }]});
  };

  const handleNewBusiness = (data: any) => {
    const newContext: FinancialContext = {
      id: `ctx_biz_${Date.now()}`,
      name: data.name,
      type: 'BUSINESS',
      accounts: [
        { id: `biz_${Date.now()}_inc`, name: 'Income', type: 'INCOME', balance: 0, subAccounts: [] },
        { id: `biz_${Date.now()}_prof`, name: 'Profit (5%)', type: 'HOLDING', balance: 0, percentageTarget: 5, subAccounts: [] },
        { id: `biz_${Date.now()}_ownr`, name: 'Owner Pay (50%)', type: 'HOLDING', balance: 0, percentageTarget: 50, subAccounts: [] },
        { id: `biz_${Date.now()}_tax`, name: 'Tax (15%)', type: 'HOLDING', balance: 0, percentageTarget: 15, subAccounts: [] },
        { id: `biz_${Date.now()}_opex`, name: 'Opex (30%)', type: 'EXPENSE', balance: 0, percentageTarget: 30, subAccounts: [] },
      ]
    };
    setState({ ...state, contexts: [...state.contexts, newContext] });
  };

  // --- Filtering ---

  const filteredTransactions = state.transactions.filter(t => 
      contextFilter === 'ALL' || t.contextId === contextFilter
  );

  const totalBalance = state.contexts
    .filter(c => contextFilter === 'ALL' || c.id === contextFilter)
    .reduce((acc, ctx) => {
        return acc + ctx.accounts.reduce((a, acc) => a + acc.balance + acc.subAccounts.reduce((s, sub) => s + sub.balance, 0), 0);
    }, 0);

  // --- Navigation Items ---
  const navItems = [
      { id: 'DASHBOARD', icon: Icons.Dashboard, label: 'Dashboard' },
      { id: 'ACCOUNTS', icon: Icons.Accounts, label: 'Vaults & Goals' },
      { id: 'TRANSACTIONS', icon: Icons.Transfer, label: 'Ledger' },
      { id: 'SUBSCRIPTIONS', icon: Icons.Subscription, label: 'Recurrences' },
      { id: 'SETTINGS', icon: Icons.Settings, label: 'System' },
