                    >
                        <option value="ALL">Global Overview</option>
                        {state.contexts.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                    </select>
                     <div className="absolute right-0 top-1/2 -translate-y-1/2 pointer-events-none">
                        <Icons.Expense className="w-3 h-3 text-alloy" />
                    </div>
                </div>
            </div>

            <div className="text-right">
                <p className="text-[10px] text-graphite uppercase tracking-widest mb-1">Total Net Worth</p>
                <span className="text-onyx font-display font-bold text-2xl">${totalBalance.toLocaleString()}</span>
