        </header>

        {/* Scrollable Area */}
        <div className="flex-1 overflow-y-auto p-4 md:p-10">

            {/* Quick Actions */}
            <div className="grid grid-cols-3 md:grid-cols-6 gap-4 mb-10">
                {[
                    { label: 'Expense', icon: Icons.Expense, action: () => setActiveModal('EXPENSE') },
                    { label: 'Income', icon: Icons.Income, action: () => setActiveModal('INCOME') },
                    { label: 'Transfer', icon: Icons.Transfer, action: () => setActiveModal('TRANSFER') },
