                                        </td>
                                        <td className={`p-5 text-right font-mono font-bold ${t.type === 'INCOME' ? 'text-onyx' : 'text-graphite'}`}>
                                            ${t.amount.toLocaleString()}
                                        </td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>
                </div>
            )}

            {currentView === 'SUBSCRIPTIONS' && (
                 <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                    {state.subscriptions.map(s => (
                        <div key={s.id} className="bg-white border border-black/5 p-6 relative group hover:border-alloy transition-colors">
                            <div className="flex justify-between items-start mb-4">
                                <div className="p-3 bg-stone">
                                    <Icons.Subscription className="w-6 h-6 text-onyx" />
                                </div>
                                <div className={`px-2 py-1 text-[10px] uppercase tracking-widest font-bold ${s.active ? 'bg-green-100 text-green-800' : 'bg-gray-100 text-gray-500'}`}>
                                    {s.active ? 'Active' : 'Paused'}
                                </div>
                            </div>
                            <h3 className="text-lg font-display font-bold text-onyx mb-1">{s.name}</h3>
                            <p className="text-xs text-graphite mb-6 uppercase tracking-wider">{s.frequency} Renewal</p>

                            <div className="flex justify-between items-end border-t border-black/5 pt-4">
                                <div>
                                    <p className="text-[10px] text-gray-400 uppercase tracking-wider">Next Billing</p>
                                    <p className="text-sm font-medium text-onyx">{s.nextRenewal}</p>
                                </div>
                                <span className="text-xl font-display font-bold text-onyx">${s.amount}</span>
                            </div>
                        </div>
                    ))}
                    <button onClick={() => setActiveModal('SUBSCRIPTION')} className="border-2 border-dashed border-black/10 flex flex-col items-center justify-center p-6 text-graphite hover:border-alloy hover:text-alloy transition-colors group h-full min-h-[200px]">
                        <Icons.Plus className="w-8 h-8 mb-2 group-hover:scale-110 transition-transform" />
                        <span className="font-display font-bold text-sm uppercase tracking-widest">Add Subscription</span>
                    </button>
                 </div>
            )}

            {currentView === 'SETTINGS' && (
                <div className="max-w-2xl mx-auto space-y-8 animate-in slide-in-from-bottom-4 duration-500">
                    <div className="bg-white border border-black/5 p-8 shadow-sm relative overflow-hidden">
                        <div className="absolute top-0 left-0 w-1 h-full bg-alloy"></div>
                        <h2 className="text-2xl font-display font-bold text-onyx mb-6">System Configuration</h2>

                        <div className="space-y-6">
                            <div>
                                <label className="block text-xs font-bold text-graphite uppercase tracking-wider mb-2">Profile Name</label>
                                <input type="text" value={state.user.name} readOnly className="w-full p-3 bg-stone border border-black/5 text-onyx font-sans" />
                            </div>
                            <div>
                                <label className="block text-xs font-bold text-graphite uppercase tracking-wider mb-2">Email Identity</label>
                                <input type="email" value={state.user.email} readOnly className="w-full p-3 bg-stone border border-black/5 text-onyx font-sans" />
                            </div>
                            <div className="flex items-center gap-4 pt-4">
                                <button className="px-6 py-3 bg-onyx text-white font-display font-bold text-xs uppercase tracking-widest hover:bg-graphite transition-colors">
                                    Update Credentials
                                </button>
                            </div>
                        </div>
                    </div>

                    <div className="bg-white border border-black/5 p-8 shadow-sm relative overflow-hidden group">
                        <div className="absolute top-0 left-0 w-1 h-full bg-gold"></div>
                        <div className="flex items-start justify-between mb-4">
                            <div>
                                <h3 className="text-xl font-display font-bold text-onyx">Business Expansion</h3>
                                <p className="text-sm text-graphite mt-2 max-w-md">Initialize a new Profit First entity structure. This will create a dedicated workspace with separated Income, Profit, Tax, Owner Pay, and Opex accounts.</p>
                            </div>
                            <Icons.Building className="w-8 h-8 text-gold opacity-50" />
                        </div>
                        <button onClick={() => setActiveModal('NEW_BIZ')} className="mt-4 px-6 py-3 border border-gold text-gold hover:bg-gold hover:text-white font-display font-bold text-xs uppercase tracking-widest transition-all">
                            Initialize New Entity
                        </button>
                    </div>
                </div>
            )}
        </div>
      </main>

      {/* Modals */}
      {activeModal === 'EXPENSE' && <TransactionForm type="EXPENSE" state={state} onSubmit={handleTransaction} onClose={() => setActiveModal(null)} />}
      {activeModal === 'INCOME' && <TransactionForm type="INCOME" state={state} onSubmit={handleTransaction} onClose={() => setActiveModal(null)} />}
      {activeModal === 'TRANSFER' && <TransferForm state={state} onSubmit={handleTransfer} onClose={() => setActiveModal(null)} />}
      {activeModal === 'CATEGORY' && <CategoryForm onSubmit={handleNewCategory} onClose={() => setActiveModal(null)} />}
      {activeModal === 'SUB_ACCOUNT' && <SubAccountForm state={state} onSubmit={handleNewSubAccount} onClose={() => setActiveModal(null)} />}
      {activeModal === 'SUBSCRIPTION' && <SubscriptionForm state={state} onSubmit={handleNewSubscription} onClose={() => setActiveModal(null)} />}
      {activeModal === 'NEW_BIZ' && <NewContextForm onSubmit={handleNewBusiness} onClose={() => setActiveModal(null)} />}

    </div>
  );
}

export default App;

export type ContextType = 'PERSONAL' | 'BUSINESS';

export interface SubAccount {
  id: string;
  name: string;
  balance: number;
  target?: number; // If set, it's a goal
  startDate: string;
}

export interface Account {
  id: string;
  name: string; // e.g., Income, Profit, Owner Pay, Needs, etc.
  type: 'INCOME' | 'EXPENSE' | 'HOLDING'; // Holding is for distribution accounts
  balance: number;
  percentageTarget?: number; // For Profit First logic (e.g., 5, 50, 15, 30)
  subAccounts: SubAccount[];
}

export interface FinancialContext {
  id: string;
  name: string; // "Personal", "Business 1", "Business 2"
  type: ContextType;
  accounts: Account[];
}

export interface Category {
  id: string;
  name: string;
  color: string;
  icon: string;
  budget?: number;
}

export interface Transaction {
  id: string;
  type: 'EXPENSE' | 'INCOME' | 'TRANSFER';
  amount: number;
  date: string; // ISO string
  notes?: string;
  contextId: string;
  accountId: string;
  subAccountId?: string;
  categoryId?: string;
  // For transfers
  toContextId?: string;
  toAccountId?: string;
  toSubAccountId?: string;
}

export interface Subscription {
  id: string;
  name: string;
  amount: number;
  frequency: 'WEEKLY' | 'MONTHLY' | 'QUARTERLY' | 'ANNUAL';
  nextRenewal: string;
  contextId: string;
  accountId: string;
  subAccountId?: string;
  categoryId?: string;
  paymentMethod: string;
  active: boolean;
}

export interface AppState {
  contexts: FinancialContext[];
  transactions: Transaction[];
  subscriptions: Subscription[];
  categories: Category[];
  user: {
    name: string;
    email: string;
    currency: string;
    darkMode: boolean;
    language: 'ES' | 'EN';
  };
}

