                    <h3 className="font-display font-bold text-lg text-onyx">Income vs. Expenses</h3>
                    <p className="font-sans text-[10px] text-graphite uppercase tracking-widest mt-1">Total Period</p>
                </div>
                <div className="w-8 h-[2px] bg-metallic"></div>
            </div>
            <ResponsiveContainer width="100%" height="80%">
                <BarChart data={data} barSize={60}>
