    const activeContext = state.contexts.find(c => c.id === contextId);
    const activeAccount = activeContext?.accounts.find(a => a.id === accountId);

    // Filter categories by selected context
    const availableCategories = state.categories.filter(c => c.contextId === contextId);

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        onSubmit({ type, contextId, accountId, subAccountId, amount: Number(amount), categoryId, date, notes });
        onClose();
    };

    return (
        <Modal isOpen={true} onClose={onClose} title={`Register ${type === 'EXPENSE' ? 'Expense' : 'Income'}`}>
            <form onSubmit={handleSubmit}>
                <div className="grid grid-cols-2 gap-4">
                    <Select label="Context" value={contextId} onChange={(e: any) => { setContextId(e.target.value); setCategoryId(''); }}>
                        {state.contexts.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                    </Select>
                    <Input type="date" label="Date" value={date} onChange={(e: any) => setDate(e.target.value)} />
                </div>

                <Input type="number" label="Amount" required min="0" step="0.01" value={amount} placeholder="0.00" onChange={(e: any) => setAmount(e.target.value)} />
                <Input type="text" label="Description" required placeholder="e.g. Client Payment, Office Rent" onChange={(e: any) => setNotes(e.target.value)} />

                <Select label="Account" value={accountId} onChange={(e: any) => { setAccountId(e.target.value); setSubAccountId(''); }}>
                    <option value="">Select Account</option>
                    {activeContext?.accounts.map(a => <option key={a.id} value={a.id}>{a.name}</option>)}
                </Select>

                {activeAccount && activeAccount.subAccounts.length > 0 && (
                    <Select label="Sub-Account (Optional)" value={subAccountId} onChange={(e: any) => setSubAccountId(e.target.value)}>
                        <option value="">None</option>
                        {activeAccount.subAccounts.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                    </Select>
                )}

                {type === 'EXPENSE' && (
                    <Select label="Category" value={categoryId} onChange={(e: any) => setCategoryId(e.target.value)}>
                        <option value="">Select Category</option>
                        {availableCategories.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                    </Select>
                )}

                <button type="submit" className={`w-full py-4 mt-4 font-display font-bold uppercase tracking-widest text-sm text-white transition-all hover:opacity-90 ${type === 'EXPENSE' ? 'bg-red-900' : 'bg-green-900'}`}>
                    Confirm {type === 'EXPENSE' ? 'Expense' : 'Income'}
                </button>
            </form>
        </Modal>
    );
};

