interface ChartsProps {
  transactions: Transaction[];
  categories: Category[];
  currency: string;
}

const formatCurrency = (amount: number, currency: string) => {
    const symbol = currency === 'USD' ? '$' : (currency === 'EUR' ? '€' : '$');
    const formatted = new Intl.NumberFormat('es-ES', { minimumFractionDigits: 0, maximumFractionDigits: 0 }).format(amount);
    // Currency symbol placement: 2.000 € (Euro standard) vs $2,000 (US). 
    // Prompt asked for "Simbolo ... no letras". 
    // Using standard mapping:
    return currency === 'EUR' ? `${formatted} ${symbol}` : `${symbol} ${formatted}`;
};

export const CashFlowChart: React.FC<ChartsProps> = ({ transactions, currency }) => {
  // Aggregate data by date
  const data = transactions.reduce((acc: any[], t) => {
    const date = t.date.split('T')[0];
    const existing = acc.find(d => d.date === date);

    if (existing) {
      if (t.type === 'INCOME') existing.income += t.amount;
      if (t.type === 'EXPENSE') existing.expense += t.amount;
    } else {
      acc.push({
        date,
        income: t.type === 'INCOME' ? t.amount : 0,
        expense: t.type === 'EXPENSE' ? t.amount : 0
      });
    }
    return acc;
  }, []).sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime());

  // Fill gaps for last 7 days if empty
  if (data.length < 7) {
      const existingDates = new Set(data.map(d => d.date));
      const today = new Date();
      for(let i=6; i>=0; i--) {
          const d = new Date(today);
          d.setDate(d.getDate() - i);
          const iso = d.toISOString().split('T')[0];
          if (!existingDates.has(iso)) {
              data.push({ date: iso, income: 0, expense: 0 });
          }
      }
      data.sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime());
  }

  return (
    <div className="h-[400px] w-full bg-white p-6 border border-black/5 hover:border-alloy transition-colors group">
      <div className="flex justify-between items-center mb-6">
          <div>
            <h3 className="font-display font-bold text-lg text-onyx">Tendencia de Flujo de Efectivo</h3>
            <p className="font-sans text-[10px] text-graphite uppercase tracking-widest mt-1">Velocidad (Últimos 7 Días)</p>
          </div>
          <div className="w-8 h-[2px] bg-metallic"></div>
      </div>
      <ResponsiveContainer width="100%" height="85%">
        <AreaChart data={data}>
          <defs>
            <linearGradient id="colorIncome" x1="0" y1="0" x2="0" y2="1">
              <stop offset="5%" stopColor="#0E0E0F" stopOpacity={0.1}/>
              <stop offset="95%" stopColor="#0E0E0F" stopOpacity={0}/>
            </linearGradient>
            <linearGradient id="colorExpense" x1="0" y1="0" x2="0" y2="1">
              <stop offset="5%" stopColor="#D4A853" stopOpacity={0.1}/>
              <stop offset="95%" stopColor="#D4A853" stopOpacity={0}/>
            </linearGradient>
          </defs>
          <XAxis dataKey="date" stroke="#9ca3af" fontSize={10} tickFormatter={(val) => val.slice(5)} tickLine={false} axisLine={false} />
          <YAxis stroke="#9ca3af" fontSize={10} tickLine={false} axisLine={false} tickFormatter={(val) => `${val}`} />
          <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f3f4f6" />
          <Tooltip 
            contentStyle={{ backgroundColor: '#0E0E0F', border: 'none', borderRadius: '0px', color: '#fff' }}
            itemStyle={{ color: '#fff', fontSize: '12px', fontFamily: 'Inter' }}
            formatter={(value: number) => formatCurrency(value, currency)}
            cursor={{ stroke: '#C9A86A', strokeWidth: 1 }}
          />
          <Area type="monotone" dataKey="income" name="Ingresos" stroke="#0E0E0F" strokeWidth={2} fillOpacity={1} fill="url(#colorIncome)" />
          <Area type="monotone" dataKey="expense" name="Gastos" stroke="#D4A853" strokeWidth={2} fillOpacity={1} fill="url(#colorExpense)" />
        </AreaChart>
      </ResponsiveContainer>
    </div>
  );
};

