export const ExpenseBreakdown: React.FC<ChartsProps> = ({ transactions, categories, currency }) => {
  const data = transactions
    .filter(t => t.type === 'EXPENSE' && t.categoryId)
    .reduce((acc: any[], t) => {
      const cat = categories.find(c => c.id === t.categoryId);
      if (!cat) return acc;

      const existing = acc.find(d => d.name === cat.name);
      if (existing) {
        existing.value += t.amount;
      } else {
        acc.push({ name: cat.name, value: t.amount, color: cat.color });
      }
      return acc;
    }, []);

  if (data.length === 0) {
      data.push({ name: 'Sin Datos', value: 100, color: '#DEDEDE' });
  }

  return (
    <div className="h-[350px] w-full bg-white p-6 border border-black/5 hover:border-alloy transition-colors">
       <div className="flex justify-between items-center mb-6">
          <div>
            <h3 className="font-display font-bold text-lg text-onyx">Desglose por Categorías</h3>
            <p className="font-sans text-[10px] text-graphite uppercase tracking-widest mt-1">Análisis de Gastos</p>
          </div>
          <div className="w-8 h-[2px] bg-metallic"></div>
      </div>
      <ResponsiveContainer width="100%" height="80%">
        <PieChart>
          <Pie
            data={data}
            cx="50%"
            cy="50%"
            innerRadius={60}
            outerRadius={80}
            paddingAngle={2}
            dataKey="value"
            stroke="none"
          >
            {data.map((entry, index) => (
              <Cell key={`cell-${index}`} fill={entry.color} />
            ))}
          </Pie>
          <Tooltip 
            contentStyle={{ backgroundColor: '#0E0E0F', border: 'none', borderRadius: '0px', color: '#fff' }}
            itemStyle={{ color: '#fff', fontSize: '12px' }}
            formatter={(value: number) => formatCurrency(value, currency)}
          />
          <Legend 
            wrapperStyle={{ fontSize: '11px', fontFamily: 'Inter', color: '#4B4B4D' }}
            layout="vertical" verticalAlign="middle" align="right" 
          />
        </PieChart>
      </ResponsiveContainer>
