      {activeModal === 'CATEGORY' && <CategoryForm state={state} onSubmit={handleNewCategory} onClose={() => setActiveModal(null)} />}
      {activeModal === 'EDIT_CATEGORY' && selectedCategory && <CategoryForm state={state} initialData={selectedCategory} onSubmit={handleUpdateCategory} onClose={() => setActiveModal(null)} />}
      {activeModal === 'SUB_ACCOUNT' && <SubAccountForm state={state} onSubmit={handleNewSubAccount} onClose={() => setActiveModal(null)} />}
      {activeModal === 'SUBSCRIPTION' && <SubscriptionForm state={state} onSubmit={handleNewSubscription} onClose={() => setActiveModal(null)} />}
      {activeModal === 'EDIT_SUBSCRIPTION' && selectedSubscription && <SubscriptionForm state={state} initialData={selectedSubscription} onSubmit={handleUpdateSubscription} onClose={() => setActiveModal(null)} />}
      {activeModal === 'NEW_BIZ' && <NewContextForm onSubmit={handleNewBusiness} onClose={() => setActiveModal(null)} />}

    </div>
  );
}

export default App;

export type ContextType = 'PERSONAL' | 'BUSINESS';

export interface SubAccount {
  id: string;
  name: string;
  balance: number;
  target?: number; // If set, it's a goal
  startDate: string;
}

export interface Account {
  id: string;
  name: string; // e.g., Income, Profit, Owner Pay, Needs, etc.
  type: 'INCOME' | 'EXPENSE' | 'HOLDING'; // Holding is for distribution accounts
  balance: number;
  percentageTarget?: number; // For Profit First logic (e.g., 5, 50, 15, 30)
  subAccounts: SubAccount[];
}

export interface FinancialContext {
  id: string;
  name: string; // "Personal", "Business 1", "Business 2"
  type: ContextType;
  accounts: Account[];
}

export interface Category {
  id: string;
  name: string;
  color: string;
  icon: string;
  budget?: number;
  contextId: string;
  accountId?: string;    // New: Link to Account
  subAccountId?: string; // New: Link to SubAccount (Optional)
}

export interface Transaction {
  id: string;
  type: 'EXPENSE' | 'INCOME' | 'TRANSFER';
  amount: number;
  date: string; // ISO string with Time
  notes?: string;
  contextId: string;
  accountId: string;
  subAccountId?: string;
  categoryId?: string;
  // For transfers
  toContextId?: string;
  toAccountId?: string;
  toSubAccountId?: string;
}

export interface Subscription {
  id: string;
  name: string;
  amount: number;
  frequency: 'WEEKLY' | 'MONTHLY' | 'QUARTERLY' | 'ANNUAL';
  nextRenewal: string;
  contextId: string;
  accountId: string;
  subAccountId?: string;
  categoryId?: string;
  paymentMethod: string;
  active: boolean;
}

export interface AppState {
  contexts: FinancialContext[];
  transactions: Transaction[];
  subscriptions: Subscription[];
  categories: Category[];
  user: {
    name: string;
    email: string;
    currency: string;
    darkMode: boolean;
    language: 'ES' | 'EN';
    timezone: string; // New: Timezone support
  };
}

