                                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                        {context.accounts.filter(a => a.type !== 'INCOME').map(account => (
                                            <div key={account.id} className="flex items-center justify-between p-3 bg-stone border border-black/5">
                                                <span className="font-bold text-sm text-onyx">{account.name}</span>
                                                <div className="flex items-center">
                                                    <input 
                                                        type="number" 
                                                        min="0" 
                                                        max="100"
                                                        value={account.percentageTarget || 0} 
                                                        onChange={(e) => handleUpdateAccountPercentage(context.id, account.id, Number(e.target.value))}
                                                        className="w-16 p-2 text-right bg-white border border-black/10 font-mono font-bold text-onyx outline-none focus:border-alloy"
                                                    />
                                                    <span className="ml-2 text-graphite font-bold">%</span>
                                                </div>
                                            </div>
                                        ))}
                                        {/* Show Total Allocation */}
                                        <div className="col-span-full flex justify-end mt-2">
                                            <span className="text-xs uppercase tracking-wider font-bold text-graphite mr-2">Total Asignado:</span>
                                            <span className={`text-sm font-mono font-bold ${context.accounts.reduce((sum, a) => sum + (a.percentageTarget || 0), 0) === 100 ? 'text-green-600' : 'text-onyx'}`}>
                                                {context.accounts.reduce((sum, a) => sum + (a.percentageTarget || 0), 0)}%
                                            </span>
                                        </div>
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>

                    <div className="bg-white border border-black/5 p-8 shadow-sm relative overflow-hidden">
                        <div className="absolute top-0 left-0 w-1 h-full bg-alloy"></div>
                        <h2 className="text-2xl font-display font-bold text-onyx mb-6">{t.profile}</h2>

                        <div className="space-y-6">
                            <div>
                                <label className="block text-xs font-bold text-graphite uppercase tracking-wider mb-2">Nombre</label>
                                <input type="text" value={state.user.name} readOnly className="w-full p-3 bg-stone border border-black/5 text-onyx font-sans" />
                            </div>
                            <div>
                                <label className="block text-xs font-bold text-graphite uppercase tracking-wider mb-2">{t.email}</label>
                                <input type="email" value={state.user.email} readOnly className="w-full p-3 bg-stone border border-black/5 text-onyx font-sans" />
                            </div>
                        </div>
                    </div>

                    <div className="bg-white border border-black/5 p-8 shadow-sm relative overflow-hidden group">
                        <div className="absolute top-0 left-0 w-1 h-full bg-gold"></div>
                        <div className="flex items-start justify-between mb-4">
                            <div>
                                <h3 className="text-xl font-display font-bold text-onyx">{t.businessExp}</h3>
                                <p className="text-sm text-graphite mt-2 max-w-md">Inicializar una nueva estructura de negocio Profit First. Esto creará un espacio de trabajo dedicado con cuentas separadas para Ingresos, Ganancias, Impuestos, Pago del Propietario y Operaciones.</p>
                            </div>
                            <Icons.Building className="w-8 h-8 text-gold opacity-50" />
                        </div>
                        <button onClick={() => setActiveModal('NEW_BIZ')} className="mt-4 px-6 py-3 border border-gold text-gold hover:bg-gold hover:text-white font-display font-bold text-xs uppercase tracking-widest transition-all">
                            {t.initializeBiz}
                        </button>
                    </div>
                </div>
            )}
        </div>
      </main>

      {/* Modals */}
      {activeModal === 'EXPENSE' && <TransactionForm type="EXPENSE" state={state} onSubmit={handleTransaction} onClose={() => setActiveModal(null)} />}
      {activeModal === 'INCOME' && <TransactionForm type="INCOME" state={state} onSubmit={handleTransaction} onClose={() => setActiveModal(null)} />}
      {activeModal === 'TRANSFER' && <TransferForm state={state} onSubmit={handleTransfer} onClose={() => setActiveModal(null)} />}
      {activeModal === 'CATEGORY' && <CategoryForm state={state} onSubmit={handleNewCategory} onClose={() => setActiveModal(null)} />}
      {activeModal === 'EDIT_CATEGORY' && selectedCategory && <CategoryForm state={state} initialData={selectedCategory} onSubmit={handleUpdateCategory} onClose={() => setActiveModal(null)} />}
      {activeModal === 'SUB_ACCOUNT' && <SubAccountForm state={state} onSubmit={handleNewSubAccount} onClose={() => setActiveModal(null)} />}
      {activeModal === 'SUBSCRIPTION' && <SubscriptionForm state={state} onSubmit={handleNewSubscription} onClose={() => setActiveModal(null)} />}
      {activeModal === 'EDIT_SUBSCRIPTION' && selectedSubscription && <SubscriptionForm state={state} initialData={selectedSubscription} onSubmit={handleUpdateSubscription} onClose={() => setActiveModal(null)} />}
      {activeModal === 'NEW_BIZ' && <NewContextForm onSubmit={handleNewBusiness} onClose={() => setActiveModal(null)} />}

    </div>
  );
}

export default App;

import React, { useState, useEffect } from 'react';
import { Icons } from './Icons';
import { AppState, Category, FinancialContext, Subscription } from '../types';

interface ModalProps {
  isOpen: boolean;
  onClose: () => void;
  title: string;
  children: React.ReactNode;
}

const Modal: React.FC<ModalProps> = ({ isOpen, onClose, title, children }) => {
  if (!isOpen) return null;
  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-onyx/80 backdrop-blur-sm p-4 animate-in fade-in duration-200">
      <div className="bg-white w-full max-w-lg shadow-[0_4px_24px_rgba(0,0,0,0.2)] border border-alloy flex flex-col max-h-[90vh]">
        <div className="p-5 border-b border-black/5 flex justify-between items-center bg-stone">
          <h2 className="text-xl font-display font-bold text-onyx uppercase tracking-tight">{title}</h2>
          <button onClick={onClose} className="p-2 hover:bg-concrete transition-colors text-onyx">
            <Icons.Close className="w-5 h-5" />
          </button>
        </div>
        <div className="p-6 overflow-y-auto">
          {children}
        </div>
        <div className="h-1 w-full bg-metallic"></div>
      </div>
    </div>
  );
};

// --- Generic Form Field Helpers ---

const Input = (props: any) => (
    <div className="mb-5 group">
        <label className="block text-xs font-bold text-graphite uppercase tracking-wider mb-2">{props.label}</label>
        <div className="relative">
            <input 
                {...props} 
                onClick={(e) => {
                    // Try to open picker on click for date inputs
                    if (props.type === 'date' || props.type === 'datetime-local') {
                        try { (e.target as HTMLInputElement).showPicker(); } catch(err) {}
                    }
                    if (props.onClick) props.onClick(e);
                }}
                className="w-full px-4 py-3 bg-white border-b border-black/20 focus:border-alloy outline-none transition-all text-onyx font-sans placeholder:text-gray-300 rounded-none" 
            />
            <div className="absolute bottom-0 left-0 h-[1px] w-0 bg-alloy transition-all duration-300 group-focus-within:w-full"></div>
        </div>
    </div>
);

const Select = (props: any) => (
    <div className="mb-5 group">
        <label className="block text-xs font-bold text-graphite uppercase tracking-wider mb-2">{props.label}</label>
        <div className="relative">
            <select {...props} className="w-full px-4 py-3 bg-white border-b border-black/20 focus:border-alloy outline-none transition-all text-onyx font-sans rounded-none appearance-none">
                {props.children}
            </select>
            <div className="absolute right-3 top-1/2 -translate-y-1/2 pointer-events-none">
                <Icons.Expense className="w-4 h-4 text-gray-400" />
            </div>
            <div className="absolute bottom-0 left-0 h-[1px] w-0 bg-alloy transition-all duration-300 group-focus-within:w-full"></div>
        </div>
    </div>
);

// --- Specific Forms ---

interface TransactionFormProps {
    type: 'EXPENSE' | 'INCOME';
    state: AppState;
    onSubmit: (data: any) => void;
    onClose: () => void;
}

export const TransactionForm: React.FC<TransactionFormProps> = ({ type, state, onSubmit, onClose }) => {
    const [contextId, setContextId] = useState(state.contexts[0]?.id || '');
    const [accountId, setAccountId] = useState('');
    const [subAccountId, setSubAccountId] = useState('');
    const [amount, setAmount] = useState('');
    const [categoryId, setCategoryId] = useState('');
    const [dateTime, setDateTime] = useState(new Date().toISOString().slice(0, 16));
    const [notes, setNotes] = useState('');
    const [distribute, setDistribute] = useState(false);

    const activeContext = state.contexts.find(c => c.id === contextId);
    const activeAccount = activeContext?.accounts.find(a => a.id === accountId);

    useEffect(() => {
        if (type === 'INCOME' && activeContext) {
            const incAcc = activeContext.accounts.find(a => a.type === 'INCOME');
            if (incAcc) setAccountId(incAcc.id);
        }
    }, [type, activeContext]);

    const availableCategories = state.categories.filter(c => c.contextId === contextId);

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        const isoDate = new Date(dateTime).toISOString();

        onSubmit({ 
            type, contextId, accountId, subAccountId, 
            amount: Number(amount), categoryId, date: isoDate, notes,
            distribute
        });
        onClose();
    };

    return (
        <Modal isOpen={true} onClose={onClose} title={`Registrar ${type === 'EXPENSE' ? 'Gasto' : 'Ingreso'}`}>
            <form onSubmit={handleSubmit}>
                <div className="grid grid-cols-2 gap-4">
                    <Select label="Espacio (Contexto)" value={contextId} onChange={(e: any) => { setContextId(e.target.value); setCategoryId(''); }}>
                        {state.contexts.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                    </Select>
                    <Input type="datetime-local" label="Fecha y Hora" value={dateTime} onChange={(e: any) => setDateTime(e.target.value)} />
                </div>

                <Input type="number" label="Monto" required min="0" step="0.01" value={amount} placeholder="0.00" onChange={(e: any) => setAmount(e.target.value)} />
                <Input type="text" label="Descripción" required placeholder="Ej. Pago Cliente, Renta" onChange={(e: any) => setNotes(e.target.value)} />

                <Select label="Cuenta" value={accountId} onChange={(e: any) => { setAccountId(e.target.value); setSubAccountId(''); }}>
                    <option value="">Seleccionar Cuenta</option>
                    {activeContext?.accounts.map(a => <option key={a.id} value={a.id}>{a.name}</option>)}
                </Select>

                {activeAccount && activeAccount.subAccounts.length > 0 && (
                    <Select label="Sub-Cuenta (Opcional)" value={subAccountId} onChange={(e: any) => setSubAccountId(e.target.value)}>
                        <option value="">Ninguna</option>
                        {activeAccount.subAccounts.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                    </Select>
                )}

                {type === 'INCOME' && activeAccount?.type === 'INCOME' && (
                    <div className="mb-6 p-4 bg-stone border border-black/5 flex items-start gap-3 group hover:border-alloy transition-colors">
                        <input 
                            type="checkbox" 
                            id="distribute" 
                            checked={distribute} 
                            onChange={(e) => setDistribute(e.target.checked)}
                            className="mt-1 accent-onyx w-4 h-4 cursor-pointer"
                        />
                        <label htmlFor="distribute" className="text-sm cursor-pointer">
                            <span className="block font-bold text-onyx">Distribuir automáticamente</span>
                            <span className="text-xs text-graphite">Repartir este ingreso en las cuentas según los porcentajes definidos (Profit First).</span>
                        </label>
                    </div>
                )}

                {type === 'EXPENSE' && (
                    <Select label="Categoría" value={categoryId} onChange={(e: any) => setCategoryId(e.target.value)}>
                        <option value="">Seleccionar Categoría</option>
                        {availableCategories.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                    </Select>
                )}

                <button type="submit" className={`w-full py-4 mt-4 font-display font-bold uppercase tracking-widest text-sm text-white transition-all hover:opacity-90 ${type === 'EXPENSE' ? 'bg-red-900' : 'bg-green-900'}`}>
                    Confirmar {type === 'EXPENSE' ? 'Gasto' : 'Ingreso'}
                </button>
            </form>
        </Modal>
    );
};

interface TransferFormProps {
    state: AppState;
    onSubmit: (data: any) => void;
    onClose: () => void;
}

export const TransferForm: React.FC<TransferFormProps> = ({ state, onSubmit, onClose }) => {
    const [fromContext, setFromContext] = useState(state.contexts[0]?.id || '');
    const [fromAccount, setFromAccount] = useState('');
    const [fromSub, setFromSub] = useState('');

    const [toContext, setToContext] = useState(state.contexts[0]?.id || '');
