export const CashFlowChart: React.FC<ChartsProps> = ({ transactions, currency }) => {
  // Aggregate data by date
  const data = transactions.reduce((acc: any[], t) => {
    const date = t.date.split('T')[0];
    const existing = acc.find(d => d.date === date);

    if (existing) {
      if (t.type === 'INCOME') existing.income += t.amount;
      if (t.type === 'EXPENSE') existing.expense += t.amount;
    } else {
      acc.push({
        date,
        income: t.type === 'INCOME' ? t.amount : 0,
        expense: t.type === 'EXPENSE' ? t.amount : 0
      });
    }
    return acc;
  }, []).sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime());

  // Fill gaps for last 7 days only if few data points (optional, logic preserved from previous state)
