export const ExpenseBreakdown: React.FC<ChartsProps> = ({ transactions, categories, currency }) => {
  const totalExpense = transactions
    .filter(t => t.type === 'EXPENSE')
    .reduce((sum, t) => sum + t.amount, 0);

  const data = transactions
    .filter(t => t.type === 'EXPENSE' && t.categoryId)
    .reduce((acc: any[], t) => {
      const cat = categories.find(c => c.id === t.categoryId);
      if (!cat) return acc;

      const existing = acc.find(d => d.name === cat.name);
      if (existing) {
        existing.value += t.amount;
      } else {
        acc.push({ name: cat.name, value: t.amount, color: cat.color, percent: 0 }); // init percent
      }
      return acc;
    }, []);

  // Calculate percents
  data.forEach(d => {
      d.percent = totalExpense > 0 ? Math.round((d.value / totalExpense) * 100) : 0;
  });

  if (data.length === 0) {
      data.push({ name: 'Sin Datos', value: 100, color: '#DEDEDE', percent: 0 });
  }

  return (
    <div className="h-[350px] w-full bg-white p-6 border border-black/5 hover:border-alloy transition-colors relative">
       <div className="flex justify-between items-center mb-6">
          <div>
            <h3 className="font-display font-bold text-lg text-onyx">Desglose por Categorías</h3>
            <p className="font-sans text-[10px] text-graphite uppercase tracking-widest mt-1">Análisis de Gastos</p>
          </div>
          <div className="w-8 h-[2px] bg-metallic"></div>
      </div>

      {/* Chart Container */}
      <div className="relative w-full h-[80%] flex justify-center items-center">

          {/* Centered Total Label - Perfectly Centered */}
          <div className="absolute inset-0 flex flex-col items-center justify-center pointer-events-none z-10">
             <span className="text-[9px] md:text-[10px] text-graphite uppercase tracking-widest font-bold bg-white/60 px-2 py-0.5 rounded backdrop-blur-sm">Gasto Total</span>
             <span className="text-lg md:text-xl font-display font-bold text-onyx mt-0.5">{formatCompact(totalExpense, currency)}</span>
          </div>

          <ResponsiveContainer width="100%" height="100%">
            <PieChart>
              <Pie
                data={data}
                cx="50%"
                cy="50%"
                innerRadius={60}
                outerRadius={80}
                paddingAngle={2}
                dataKey="value"
                stroke="none"
              >
                {data.map((entry, index) => (
                  <Cell key={`cell-${index}`} fill={entry.color} />
                ))}
              </Pie>
              <Tooltip content={<CustomTooltip currency={currency} type="DONUT" />} />
              <Legend 
                wrapperStyle={{ fontSize: '11px', fontFamily: 'Inter', color: '#4B4B4D' }}
                layout="vertical" verticalAlign="middle" align="right" 
              />
            </PieChart>
          </ResponsiveContainer>
      </div>
    </div>
  );
};

import React, { useState, useMemo } from 'react';
