export const ExpenseBreakdown: React.FC<ChartsProps> = ({ transactions, categories, currency }) => {
  const [isMobile, setIsMobile] = useState(window.innerWidth < 768);

  useEffect(() => {
    const handleResize = () => setIsMobile(window.innerWidth < 768);
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  const totalExpense = transactions
    .filter(t => t.type === 'EXPENSE')
    .reduce((sum, t) => sum + t.amount, 0);

  const data = transactions
    .filter(t => t.type === 'EXPENSE' && t.categoryId)
    .reduce((acc: any[], t) => {
      const cat = categories.find(c => c.id === t.categoryId);
      if (!cat) return acc;

      const existing = acc.find(d => d.name === cat.name);
      if (existing) {
        existing.value += t.amount;
      } else {
        acc.push({ name: cat.name, value: t.amount, color: cat.color, percent: 0 }); // init percent
      }
      return acc;
    }, [])
    .sort((a, b) => b.value - a.value); // Sort desc

  // Calculate percents
  data.forEach(d => {
      d.percent = totalExpense > 0 ? Math.round((d.value / totalExpense) * 100) : 0;
  });

  if (data.length === 0) {
      data.push({ name: 'Sin Datos', value: 100, color: '#DEDEDE', percent: 0 });
  }

  return (
    <div className="h-[400px] w-full bg-white p-6 border border-black/5 hover:border-alloy transition-colors relative flex flex-col">
       <div className="flex justify-between items-center mb-4 flex-shrink-0">
          <div>
            <h3 className="font-display font-bold text-lg text-onyx">Desglose por Categorías</h3>
            <p className="font-sans text-[10px] text-graphite uppercase tracking-widest mt-1">Análisis de Gastos</p>
          </div>
          {/* Total Expense Replacement for Gold Line */}
          <div className="text-right">
              <p className="font-sans text-[10px] text-graphite uppercase tracking-widest mb-1">Gasto Total</p>
              <p className="font-mono font-bold text-lg text-onyx">{formatExact(totalExpense, currency)}</p>
          </div>
      </div>

      {/* Chart & Legend Container */}
      <div className="flex-1 min-h-0 flex flex-col md:flex-row items-center gap-4">

          {/* Pie Chart */}
          <div className="w-full md:w-1/2 h-[200px] md:h-full relative">
              <ResponsiveContainer width="100%" height="100%">
                <PieChart>
                  <Pie
                    data={data}
                    cx="50%"
                    cy="50%"
                    innerRadius={isMobile ? 50 : 60}
                    outerRadius={isMobile ? 70 : 80}
                    paddingAngle={2}
                    dataKey="value"
                    stroke="none"
                  >
                    {data.map((entry, index) => (
                      <Cell key={`cell-${index}`} fill={entry.color} />
                    ))}
                  </Pie>
                  <Tooltip content={<CustomTooltip currency={currency} type="DONUT" />} />
                </PieChart>
              </ResponsiveContainer>
          </div>

          {/* Custom Detail Legend */}
          <div className="w-full md:w-1/2 h-full overflow-y-auto custom-scrollbar pr-2">
               <div className="grid grid-cols-1 gap-2">
                  {data.map((item, idx) => (
                    <div key={idx} className="flex items-center justify-between text-xs group">
                       <div className="flex items-center gap-2 truncate flex-1">
                          <div className="w-2 h-2 rounded-full flex-shrink-0" style={{backgroundColor: item.color}}></div>
                          <span className="text-onyx font-medium truncate" title={item.name}>{item.name}</span>
                       </div>
                       <div className="flex items-center gap-1 pl-2">
                           <span className="text-gray-200 hidden xl:block">.......................</span>
